import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Chip,
  Stack,
  Alert,
  Snackbar,
  LinearProgress,
  CircularProgress
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon
} from '@mui/icons-material';
import { 
  getNodes, 
  getNodeStatus, 
  updateNode, 
  deleteNode 
} from '../services/api';

const Nodes = () => {
  const [nodes, setNodes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedNode, setSelectedNode] = useState(null);
  const [editNode, setEditNode] = useState({
    name: '',
    type: 'select',
    region: '',
    subscription: '',
    excludes: [],
    includes: []
  });

  useEffect(() => {
    fetchNodes();
  }, []);

  const fetchNodes = async () => {
    try {
      setLoading(true);
      const data = await getNodes();
      setNodes(data);
    } catch (err) {
      setError('Failed to load nodes');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (node = null) => {
    if (node) {
      setSelectedNode(node);
      setEditNode(node);
    } else {
      setSelectedNode(null);
      setEditNode({
        name: '',
        type: 'select',
        region: '',
        subscription: '',
        excludes: [],
        includes: []
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedNode(null);
    setEditNode({
      name: '',
      type: 'select',
      region: '',
      subscription: '',
      excludes: [],
      includes: []
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      if (selectedNode) {
        await updateNode(selectedNode.id, editNode);
      }
      await fetchNodes();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError('Failed to save node');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteNode(id);
      await fetchNodes();
      setSuccess(true);
    } catch (err) {
      setError('Failed to delete node');
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async (id) => {
    try {
      setLoading(true);
      await getNodeStatus(id);
      await fetchNodes();
      setSuccess(true);
    } catch (err) {
      setError('Failed to refresh node status');
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'running':
        return 'success';
      case 'stopped':
        return 'error';
      case 'warning':
        return 'warning';
      default:
        return 'default';
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card 
        sx={{ 
          mb: 1.5,
          background: (theme) => 
            theme.palette.mode === 'dark' 
              ? 'linear-gradient(90deg, #1a237e 0%, #311b92 100%)'
              : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
          color: '#fff',
          boxShadow: (theme) =>
            theme.palette.mode === 'dark'
              ? '0 2px 4px -1px rgba(0,0,0,0.4)'
              : '0 2px 4px -1px rgba(0,0,0,0.2)',
        }}
      >
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                节点管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Button
              variant="outlined"
              size="small"
              startIcon={<AddIcon />}
              onClick={() => handleOpenDialog()}
              sx={{
                color: 'rgba(255,255,255,0.8)',
                borderColor: 'rgba(255,255,255,0.2)',
                '&:hover': {
                  borderColor: 'rgba(255,255,255,0.4)',
                  backgroundColor: 'rgba(255,255,255,0.1)',
                },
              }}
            >
              添加节点
            </Button>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Grid container spacing={1.5}>
        {nodes.map((node) => (
          <Grid item xs={12} sm={6} lg={4} key={node.id}>
            <Card>
              <CardContent>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                  <Typography variant="h6">{node.name}</Typography>
                  <Stack direction="row" spacing={0.5}>
                    <IconButton size="small" onClick={() => handleOpenDialog(node)}>
                      <EditIcon fontSize="small" />
                    </IconButton>
                    <IconButton size="small" onClick={() => handleDelete(node.id)}>
                      <DeleteIcon fontSize="small" />
                    </IconButton>
                  </Stack>
                </Box>
                <Stack direction="row" spacing={1} sx={{ mb: 1.5 }}>
                  <Chip 
                    label={node.type} 
                    color="primary" 
                    size="small" 
                  />
                  <Chip 
                    label={node.status ? "在线" : "离线"} 
                    color={node.status ? "success" : "error"} 
                    size="small" 
                  />
                </Stack>
                <Typography variant="body2" color="text.secondary">
                  延迟: {node.latency}ms
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Dialog open={openDialog} onClose={handleCloseDialog} maxWidth="sm" fullWidth>
        <DialogTitle>
          {selectedNode ? '编辑节点' : '添加节点'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="节点名称"
                  value={editNode.name}
                  onChange={(e) => setEditNode({ ...editNode, name: e.target.value })}
                  size="small"
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="节点类型"
                  value={editNode.type}
                  onChange={(e) => setEditNode({ ...editNode, type: e.target.value })}
                  size="small"
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog} size="small">取消</Button>
          <Button 
            variant="contained" 
            onClick={handleSave}
            disabled={loading}
            size="small"
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Nodes;
